params.script:
// 1. 各モジュールの結果を取得
var resMobile = $runner.getModuleResult("携帯電話判別");
var resOther  = $runner.getModuleResult("携帯以外");

var finalResult = 0; // デフォルト（どちらにも当てはまらない場合）

// 2. 判定ロジック
if (resMobile === "携帯") {
    // 「携帯電話判別」が「携帯」なら 1
    finalResult = 1;
} else if (resOther === "その他") {
    // 「携帯以外」が「その他」なら 2
    finalResult = 2;
}

// 3. 結果をセット
$runner.getLogger().info("判定終了: 結果=" + finalResult + " (携帯用=" + resMobile + ", その他用=" + resOther + ")");
$runner.setResult(finalResult);

var rawData = $runner.getModuleResult("電話番号正規化2");
var d = rawData ? String(rawData).replace(/[^0-9]/g, "") : "";

// 判定フラグ
var isMobile = false;

// 携帯電話の判定：060, 070, 080, 090 から始まる11桁
var mobilePattern = /^0[6-9]0\d{8}$/;

if (mobilePattern.test(d)) {
    isMobile = true;
    // 携帯電話の場合の処理
} else {
    isMobile = false;
    // それ以外（固定電話、050、020、フリーダイヤルなど）の場合の処理
}

$runner.setResult(isMobile ? "MOBILE" : "OTHER");
